using System;
using System.Collections.Generic;

// ── Per-page metadata (the WinUI Gallery ControlInfoData pattern) ──────────────────────────────────────────────────
// Each gallery page can carry: a tile subtitle, a long description, a tile image (bundled from WinUI-Gallery), the
// WinUI reference template path (relative to microsoft-ui-xaml controls/dev), the engine source + sample-page files
// (repo-relative), learn.microsoft.com doc links, and related-page keys. The WinUI-control half of the table is
// generated by scripts/extract-gallery-metadata.ps1 into PageInfoData.g.cs; engine pages are hand-authored here.

/// <summary>One documentation link: display title + target. <see cref="Uri"/> is absolute (https://…) or repo-relative
/// ("docs/guide/reactivity.md") — repo-relative targets open on GitHub via <see cref="PageInfo.Open"/>.</summary>
sealed record PageDoc(string Title, string Uri);

/// <summary>WinUI-Gallery-style per-page metadata. See the file header for field semantics.</summary>
sealed record PageMeta(
    string Key, string Subtitle, string Description,
    string? Image, string? WinUiTemplate, string? ControlSource, string? SamplePage,
    PageDoc[] Docs, string[] Related);

