    // Built lazily on first use: static field initializers across PARTIAL class files run in unspecified order, so an
    // eager `= BuildIndex()` here can run before the generated WinUiMeta initializer (NullReference at startup).
    static Dictionary<string, PageMeta>? _byKey;

    static Dictionary<string, PageMeta> ByKey => _byKey ??= BuildIndex();

    static Dictionary<string, PageMeta> BuildIndex()
    {
        var map = new Dictionary<string, PageMeta>(StringComparer.Ordinal);
        foreach (var m in WinUiMeta) map[m.Key] = m;
        foreach (var m in EngineMeta) map[m.Key] = m;
        return map;
    }

    /// <summary>Metadata for a page key (control pages use the control name; engine pages the nav key). Null when the
    /// page has no registered metadata — the shell falls back to a plain title + description header.</summary>
    public static PageMeta? Find(string key) => ByKey.TryGetValue(key, out var m) ? m : null;

    /// <summary>Related keys that actually route to a gallery page (drops WinUI-only entries).</summary>
    public static string[] RoutableRelated(PageMeta meta)
    {
        var list = new List<string>(meta.Related.Length);
        foreach (var r in meta.Related)
            if (!NonRoutable.Contains(r) && ByKey.ContainsKey(r)) list.Add(r);
        return list.ToArray();
    }

    /// <summary>Launch a doc/source link: absolute URIs open as-is; repo-relative paths open on GitHub. Routed through
    /// the <c>IPlatformApp.OpenUri</c> PAL seam (ShellExecute on Windows; recorded in headless hosts).</summary>
    public static void Open(string uri)
        => FluentGpu.Hooks.InputHooks.Current.Default.OpenUri?.Invoke(
            uri.StartsWith("http", StringComparison.Ordinal) ? uri : RepoBlobUrl + uri.Replace('\\', '/'));
}
